'use client';

import { useState } from 'react';
import { shortenUrl } from './actions';
import { Container, Box, Typography, TextField, Button, Paper, Link } from '@mui/material';

export default function Home() {
  const [url, setUrl] = useState('');
  const [shortUrl, setShortUrl] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setShortUrl('');

    const formData = new FormData(e.currentTarget);
    const result = await shortenUrl(formData);

    if (result.error) {
      setError(result.error);
    } else if (result.shortCode) {
      setShortUrl(`${window.location.origin}/${result.shortCode}`);
    }

    setLoading(false);
  };

  return (
    <Container maxWidth="sm">
      <Box sx={{ mt: 10, display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
        <Typography component="h1" variant="h3" fontWeight={700} gutterBottom>
          Shorty
        </Typography>
        <Typography variant="subtitle1" color="text.secondary" gutterBottom>
          The simplest way to shrink your URLs.
        </Typography>

        <Paper elevation={0} variant="outlined" sx={{ p: 4, width: '100%', mt: 4, borderRadius: 3 }}>
          <Box component="form" onSubmit={handleSubmit} sx={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
            <TextField
              required
              fullWidth
              label="Original URL"
              name="url"
              type="url"
              value={url}
              onChange={(e) => setUrl(e.target.value)}
              placeholder="https://example.com/very/long/url"
              variant="outlined"
            />
            <Button
              type="submit"
              fullWidth
              variant="contained"
              size="large"
              disableElevation
              disabled={loading}
              sx={{ py: 1.5, borderRadius: 2 }}
            >
              {loading ? 'Shortening...' : 'Shorten URL'}
            </Button>
          </Box>

          {error && (
            <Typography color="error" sx={{ mt: 3, textAlign: 'center', fontWeight: 500 }}>
              {error}
            </Typography>
          )}

          {shortUrl && (
            <Box sx={{ mt: 4, p: 3, bgcolor: 'success.light', borderRadius: 2, textAlign: 'center' }}>
              <Typography variant="body2" color="success.contrastText" sx={{ mb: 1, fontWeight: 500 }}>
                Your shortened URL is ready:
              </Typography>
              <Link 
                href={shortUrl} 
                target="_blank" 
                rel="noopener" 
                underline="hover"
                sx={{ 
                  color: 'success.contrastText', 
                  fontWeight: 700, 
                  fontSize: '1.2rem',
                  display: 'block', 
                  wordBreak: 'break-all' 
                }}
              >
                {shortUrl}
              </Link>
            </Box>
          )}
        </Paper>
      </Box>
    </Container>
  );
}

